import React, { useState, useEffect } from 'react';

import { Line } from 'react-chartjs-2';

import {

  Chart as ChartJS,

  CategoryScale,

  LinearScale,

  PointElement,

  LineElement,

  Title,

  Tooltip,

  Legend,

} from 'chart.js';

import { getLogs } from '../services/api';

ChartJS.register(

  CategoryScale,

  LinearScale,

  PointElement,

  LineElement,

  Title,

  Tooltip,

  Legend

);

function EmissionChart() {

  const [logs, setLogs] = useState([]);

  useEffect(() => {

    const fetchLogs = async () => {

      try {

        const response = await getLogs();

        setLogs(response.data.logs || []);

      } catch (error) {

        console.error('Error fetching logs:', error);

      }

    };

    fetchLogs();

  }, []);

  const data = {

    labels: logs.map(log => log.timestamp),

    datasets: [

      {

        label: 'CO₂ Emissions',

        data: logs.map(log => log.emission),

        borderColor: 'rgb(75, 192, 192)',

        tension: 0.1,

      },

    ],

  };

  return (

    <div>
      <h2 className="chart-title" style={{ color: '#00f0ff', marginBottom: '20px' }}>Emission Chart</h2>
      <Line data={data} options={{
        responsive: true,
        plugins: {
          legend: { labels: { color: 'white' } },
          title: { display: false }
        },
        scales: {
          x: { ticks: { color: '#888' }, grid: { color: 'rgba(255,255,255,0.1)' } },
          y: { ticks: { color: '#888' }, grid: { color: 'rgba(255,255,255,0.1)' } }
        }
      }} />
    </div>

  );

}

export default EmissionChart;
